parameters.blocksUi:
={{
[
  {
    "type": "header",
    "text": {
      "type": "plain_text",
      "text": "⚠️ Employee Onboarding Requires Review"
    }
  },
  {
    "type": "section",
    "fields": [
      {
        "type": "mrkdwn",
        "text": `*Employee:*\n${$json.employeeName}`
      },
      {
        "type": "mrkdwn",
        "text": `*ID:*\n${$json.employeeId}`
      },
      {
        "type": "mrkdwn",
        "text": `*Email:*\n${$json.email}`
      },
      {
        "type": "mrkdwn",
        "text": `*Status:*\n${$json.validationStatus}`
      }
    ]
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Missing Documents:*\n${($json.missingDocuments || []).join(", ")}`
    }
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Risk Flags:*\n${($json.riskFlags || []).join(", ")}`
    }
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*AI Recommendation:*\n${$json.recommendation}`
    }
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Confidence Score:* ${(($json.confidenceScore || 0) * 100).toFixed(0)}%`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "context",
    "elements": [
      {
        "type": "mrkdwn",
        "text": `Queued at ${$json.queuedAt} | Priority: ${$json.priority}`
      }
    ]
  }
]
}}
